#ifndef BLOCK_SIZE
#define BLOCK_SIZE 16
#endif

inline int mat_idx(int row, int col, int size) {
    return row * size + col;
}

__kernel void lud_diagonal(__global float *a,
                           __local float *shadow,
                           int size,
                           int offset)
{
    (void)shadow;

    if (get_global_id(0) != 0 || get_global_id(1) != 0)
        return;

    for (int i = 0; i < BLOCK_SIZE; i++) {
        for (int j = i; j < BLOCK_SIZE; j++) {
            float sum = a[mat_idx(offset + i, offset + j, size)];
            for (int k = 0; k < i; k++) {
                sum -= a[mat_idx(offset + i, offset + k, size)] *
                       a[mat_idx(offset + k, offset + j, size)];
            }
            a[mat_idx(offset + i, offset + j, size)] = sum;
        }

        float temp = 1.0f / a[mat_idx(offset + i, offset + i, size)];
        for (int j = i + 1; j < BLOCK_SIZE; j++) {
            float sum = a[mat_idx(offset + j, offset + i, size)];
            for (int k = 0; k < i; k++) {
                sum -= a[mat_idx(offset + j, offset + k, size)] *
                       a[mat_idx(offset + k, offset + i, size)];
            }
            a[mat_idx(offset + j, offset + i, size)] = sum * temp;
        }
    }
}

__kernel void lud_perimeter(__global float *a,
                            __local float *diag_block,
                            __local float *peri_row,
                            __local float *peri_col,
                            int size,
                            int offset)
{
    (void)diag_block;
    (void)peri_row;
    (void)peri_col;

    if (get_local_id(0) != 0 || get_local_id(1) != 0)
        return;

    int chunk_idx = (int)get_group_id(0);

    float temp[BLOCK_SIZE * BLOCK_SIZE];

    for (int i = 0; i < BLOCK_SIZE; i++) {
        for (int j = 0; j < BLOCK_SIZE; j++) {
            temp[i * BLOCK_SIZE + j] = a[mat_idx(offset + i, offset + j, size)];
        }
    }

    int i_global = offset;
    int j_global = offset + BLOCK_SIZE * (chunk_idx + 1);

    for (int j = 0; j < BLOCK_SIZE; j++) {
        for (int i = 0; i < BLOCK_SIZE; i++) {
            float sum = 0.0f;
            for (int k = 0; k < i; k++) {
                sum += temp[i * BLOCK_SIZE + k] *
                       a[mat_idx(i_global + k, j_global + j, size)];
            }
            a[mat_idx(i_global + i, j_global + j, size)] -= sum;
        }
    }

    j_global = offset;
    i_global = offset + BLOCK_SIZE * (chunk_idx + 1);

    for (int i = 0; i < BLOCK_SIZE; i++) {
        for (int j = 0; j < BLOCK_SIZE; j++) {
            float sum = 0.0f;
            for (int k = 0; k < j; k++) {
                sum += a[mat_idx(i_global + i, j_global + k, size)] *
                       temp[k * BLOCK_SIZE + j];
            }
            a[mat_idx(i_global + i, j_global + j, size)] =
                (a[mat_idx(i_global + i, j_global + j, size)] - sum) /
                a[mat_idx(offset + j, offset + j, size)];
        }
    }
}

__kernel void lud_internal(__global float *a,
                           __local float *temp_top_local,
                           __local float *temp_left_local,
                           int size,
                           int offset)
{
    (void)temp_top_local;
    (void)temp_left_local;

    if (get_local_id(0) != 0 || get_local_id(1) != 0)
        return;

    int block_col = (int)get_group_id(0);
    int block_row = (int)get_group_id(1);

    int i_global = offset + BLOCK_SIZE * (1 + block_row);
    int j_global = offset + BLOCK_SIZE * (1 + block_col);

    float temp_top[BLOCK_SIZE * BLOCK_SIZE];
    float temp_left[BLOCK_SIZE * BLOCK_SIZE];

    for (int i = 0; i < BLOCK_SIZE; i++) {
        for (int j = 0; j < BLOCK_SIZE; j++) {
            temp_top[i * BLOCK_SIZE + j] =
                a[mat_idx(offset + i, j_global + j, size)];
            temp_left[i * BLOCK_SIZE + j] =
                a[mat_idx(i_global + i, offset + j, size)];
        }
    }

    for (int i = 0; i < BLOCK_SIZE; i++) {
        float sum[BLOCK_SIZE];
        for (int j = 0; j < BLOCK_SIZE; j++) {
            sum[j] = 0.0f;
        }

        for (int k = 0; k < BLOCK_SIZE; k++) {
            float left_val = temp_left[i * BLOCK_SIZE + k];
            for (int j = 0; j < BLOCK_SIZE; j++) {
                sum[j] += left_val * temp_top[k * BLOCK_SIZE + j];
            }
        }

        for (int j = 0; j < BLOCK_SIZE; j++) {
            a[mat_idx(i_global + i, j_global + j, size)] -= sum[j];
        }
    }
}
